  # Helper to clean object strings (remove surrounding quotes if present)
      def clean_obj(o: str) -> str:
          o = o.strip()
          if (o.startswith('"') and o.endswith('"')) or (o.startswith("'") and o.endswith("'")):
              return o[1:-1]
          return o

      clauses = []
      for t in triples:
          tmpl = templates.get(t.predicate)
          obj = clean_obj(t.object)
          if tmpl:
              clause = tmpl.format(subject=t.subject, object=obj)
          else:
              # Fallback: make predicate readable
              pred = t.predicate.replace("_", " ")
              clause = f"{t.subject} {pred} {obj}"
          clauses.append(clause)

      # Combine clauses into a single fluent sentence using commas and a final "and"
      if len(clauses) == 1:
          sentence = clauses[0]
      else:
          sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1]
